function solve(grid) {
    const M = grid.length;
    const N = grid[0].length;
    const MAX_XOR = 1024; // Since grid values are <= 1023

    // DP[i][j] will store a boolean array of size 1024.
    // DP[i][j][x] is true if XOR sum x is achievable at (i, j).
    // Initialize DP table: M rows, N columns, 1024 entries each.
    const DP = Array(M).fill(0).map(() => 
        Array(N).fill(0).map(() => 
            new Array(MAX_XOR).fill(false)
        )
    );

    // Base case: (0, 0)
    DP[0][0][grid[0][0]] = true;

    for (let i = 0; i < M; i++) {
        for (let j = 0; j < N; j++) {
            if (i === 0 && j === 0) {
                continue;
            }

            const G = grid[i][j];
            const current_dp = DP[i][j];

            // 1. Calculate paths coming from above (i-1, j)
            if (i > 0) {
                const prev_dp = DP[i - 1][j];
                for (let x = 0; x < MAX_XOR; x++) {
                    if (prev_dp[x]) {
                        const newXOR = x ^ G;
                        current_dp[newXOR] = true;
                    }
                }
            }

            // 2. Calculate paths coming from left (i, j-1)
            if (j > 0) {
                const prev_dp = DP[i][j - 1];
                for (let y = 0; y < MAX_XOR; y++) {
                    if (prev_dp[y]) {
                        const newXOR = y ^ G;
                        current_dp[newXOR] = true;
                    }
                }
            }
        }
    }

    // Find the minimum achievable XOR sum at (M-1, N-1)
    const final_dp = DP[M - 1][N - 1];
    for (let x = 0; x < MAX_XOR; x++) {
        if (final_dp[x]) {
            return x;
        }
    }

    // This line should technically never be reached given the problem constraints, 
    // as at least one path always exists.
    return -1; 
}

